%[text] # 例8.8（超解像）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example08_08"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
I = im2double(imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear'));
%%
%[text] ## 幾何処理前の画像表示
figure(1) %[output:64078bdf]
imshow(I)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]
%%
%[text] ## 観測画像
rng(0)
hsigma  = 2;                    % ガウスカーネル分散
hsize   = 2*ceil(2*hsigma)+1;   % ガウスカーネルサイズ
nvar    = (10/255)^2;            % 加法性白色ガウスノイズ分散
psf = fspecial('gaussian',hsize,hsigma);   
varw = (10/255)^2;

% 測定過程
measureproc = @(x) downsample2(imfilter(x,psf,'conv','circular'),[2 2]); % H
measureadjp = @(x) imfilter(upsample2(x,[2 2]),psf,'corr','circular'); % H.'
U = measureproc(I);

% 測定過程の整合性チェック
%assert(norm(U - imresize(I,0.5,'box'),'fro')<1e-6)

% Simulation of AWGN
V = imnoise(measureproc(I),'gaussian',0,varw);

% 随伴関係 <Sx,v> = <x,S.'v> の確認
W = measureadjp(V);
assert(abs(dot(U(:),V(:))-dot(I(:),W(:)))<1e-6)

figure(2) %[output:0fce23a5]
imshow(V) %[output:0fce23a5]
title('観測画像')  %[output:0fce23a5]

%%
%[text] ### 双三次補間
Yb = imresize(V,2,'bicubic');
figure(3) %[output:59e4a8c9]
subplot(1,3,1) %[output:59e4a8c9]
imshow(Yb) %[output:59e4a8c9]
title("双三次補間 PSNR: "+num2str(psnr(I,Yb))+" dB")  %[output:59e4a8c9]
%[text] ## 
%%
%[text] ### 復元前処理
vpst = rand(size(V),'like',V);
lpre = 1.0;
err_ = Inf;
while ( err_ >  1e-5 ) % べき乗法
    % vpst = (P.'*P)*vupre
    vpre = vpst/norm(vpst(:));
    u    = measureproc(vpre); % P
    vpst = measureadjp(u);    % P.'
    n    = (vpst(:).'*vpst(:));
    d    = (vpst(:).'*vpre(:));
    lpst = n/d;
    err_ = norm(lpst-lpre);
    lpre = lpst;
end
frameBound = 1; % フレーム境界
L = frameBound*lpst;
fprintf('L = %g\n',L); %[output:3996df34]
%%
%[text] ### ラッソ正則化超解像
import msip.udhaarwtdec2
import msip.udhaarwtrec2
nlevels = 5;
[coefs,scales] = udhaarwtdec2(I,nlevels);
R = udhaarwtrec2(coefs,scales);
assert(norm(I-R,"fro")^2/numel(I)<1e-18,'Perfect reconstruction is violated.')
% 合成辞書と転置辞書の定義 (Definition of synthesis dictionary and its adjoint)
adjdic = @(x) udhaarwtdec2(x,nlevels); % D
syndic = @(x) udhaarwtrec2(x,scales);  % D.'

subplot(1,3,2)
him = imshow(zeros(size(I)));
htt = title("ラッソ正則化 PSNR: "+num2str(psnr(I,zeros(size(I))))+" dB") ;

nIters = 10000;
lambda = 2e-3;
gamma1 = 2/L-1e-3;
gamma2 = (1/gamma1)-L/2;
assert(gamma1 > 0)
assert(gamma2 > 0)
assert((1/gamma1)-gamma2 >= L/2)
S = zeros(size(coefs),'like',coefs);
X = zeros(size(I),'like',I);
for iter = 1:nIters
    g = adjdic( measureadjp( measureproc( syndic(S) ) - V ) ); 
    Spre = S;
    S = softthresh( Spre - gamma1*(g + adjdic(X)) , lambda*gamma1);
    U = X + gamma2*syndic(2*S-Spre);
    X = U - gamma2*min(max(U/gamma2,0),1);
    if mod(iter,100)==0
        Yc = syndic(S);
        him.CData = Yc;
        htt.String = "制約付きラッソ正則化 PSNR: "+num2str(psnr(I,Yc))+" dB" +"("+num2str(iter)+")";
        drawnow
    end
end
Yc = syndic(S);
%%
%[text] ### TV正則化超解像
%[text] 
%%
%[text] ## 結果出力
imwrite(V, fullfile(resfolder,"fig08-10a.png"))
imwrite(Yb,fullfile(resfolder,"fig08-10b.png"))
imwrite(Yc,fullfile(resfolder,"fig08-10c.png"))
%imwrite(Y,fullfile(resfolder,"fig01-02c.png"))
%%
%[text] ソフト閾値処理
function y = softthresh(x,lambda)
    y = x + abs(x-lambda)/2 - abs(x+lambda)/2;
end

function y = downsample2(x,M)
    z = downsample(x,M(1)).';
    y = downsample(z,M(2)).';
end

function y = upsample2(x,M)
    z = upsample(x,M(1)).';
    y = upsample(z,M(2)).';
end
